const normalized = $('Merge Inputs').first().json;   // <-- the payload with type+body+ids
const type = normalized.type;

const api = $input.first().json;

let azimuth = null;

if (type === 'SunAzimuth') {
  azimuth = api?.sun_azimuth ?? api?.sun?.azimuth ?? api?.data?.sun_azimuth ?? api?.data?.sun?.azimuth;
} else if (type === 'MoonAzimuth') {
  azimuth = api?.moon_azimuth ?? api?.moon?.azimuth ?? api?.data?.moon_azimuth ?? api?.data?.moon?.azimuth;
}

if (azimuth == null) {
  return [{
    json: { statusCode: 500, error: `${type} azimuth missing`, rawApi: api }
  }];
}

return [{
  json: {
    ...normalized,
    azimuth: Number(azimuth)
  }
}];

const n = $('Normalize').first().json;
const claim = $json; // Try Claim Slot output

return [{
